module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output reg [DATA_WIDTH:0] result,
    output reg o_en
);

    reg [63:0] adda_reg1, adda_reg2, adda_reg3, adda_reg4;
    reg [63:0] addb_reg1, addb_reg2, addb_reg3, addb_reg4;
    reg [64:0] sum_stage1, sum_stage2, sum_stage3, sum_stage4;
    reg carry_stage1, carry_stage2, carry_stage3, carry_stage4;
    reg i_en_reg1, i_en_reg2, i_en_reg3, i_en_reg4;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg1 <= 0;
            addb_reg1 <= 0;
            i_en_reg1 <= 0;
        end else begin
            adda_reg1 <= adda;
            addb_reg1 <= addb;
            i_en_reg1 <= i_en;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_stage1 <= 0;
            carry_stage1 <= 0;
        end else begin
            {carry_stage1, sum_stage1} <= adda_reg1 + addb_reg1;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_stage2 <= 0;
            carry_stage2 <= 0;
        end else begin
            {carry_stage2, sum_stage2} <= sum_stage1 + carry_stage1;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_stage3 <= 0;
            carry_stage3 <= 0;
        end else begin
            {carry_stage3, sum_stage3} <= sum_stage2 + carry_stage2;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_stage4 <= 0;
            carry_stage4 <= 0;
        end else begin
            {carry_stage4, sum_stage4} <= sum_stage3 + carry_stage3;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            result <= 0;
            o_en <= 0;
        end else begin
            result <= sum_stage4;
            o_en <= i_en_reg4;
        end
    end

endmodule
